namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new NotificationItem { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > lastId).ToList();
            return Task.FromResult(newer);
        }
    }

    public void SimulateNewNotification()
    {
        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = $"New event at {DateTime.UtcNow:HH:mm:ss}",
                Timestamp = DateTime.UtcNow
            });
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Timestamp.ToString("HH:mm:ss")</strong> &mdash; @n.Message
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<NotificationItem>? PersistedNotifications { get; set; }

    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        if (PersistedNotifications is not null)
        {
            notifications = PersistedNotifications;
        }
        else
        {
            notifications = await NotificationService.GetNotificationsAsync();
            PersistedNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct);

            // Simulate new notifications arriving server-side
            NotificationService.SimulateNewNotification();

            var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                PersistedNotifications = notifications;
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

